            ViewBag.ProductId = id;
            ViewBag.ProductName = $"Product {id}"; // Placeholder product name

            var reviews = _reviews.Where(r => r.ProductId == id).ToList();

            // Apply basic formatting transformation
            foreach (var review in reviews)
            {
                review.FormattedText = FormatReviewText(review.Text);
            }

            return View(reviews);
        }

        private string FormatReviewText(string rawText)
        {
            // Simple markdown-like formatting:
            // **text** or <b>text</b> for bold
            // *text* or _text_ for italic
            string formattedText = rawText;

            // Replace **text** with <b>text</b>
            formattedText = System.Text.RegularExpressions.Regex.Replace(formattedText, @"\*\*(.*?)\*\*", "<b>$1</b>");
            // Replace <b>text</b> with <b>text</b> (in case user explicitly used HTML)
            formattedText = System.Text.RegularExpressions.Regex.Replace(formattedText, @"&lt;b&gt;(.*?)&lt;/b&gt;", "<b>$1</b>", System.Text.RegularExpressions.RegexOptions.IgnoreCase);


            // Replace *text* with <i>text</i>
            formattedText = System.Text.RegularExpressions.Regex.Replace(formattedText, @"\*(.*?)\*", "<i>$1</i>");
            // Replace _text_ with <i>text</i>
            formattedText = System.Text.RegularExpressions.Regex.Replace(formattedText, @"_(.*?)_", "<i>$1</i>");
            // Replace <i>text</i> with <i>text</i> (in case user explicitly used HTML)
            formattedText = System.Text.RegularExpressions.Regex.Replace(formattedText, @"&lt;i&gt;(.*?)&lt;/i&gt;", "<i>$1</i>", System.Text.RegularExpressions.RegexOptions.IgnoreCase);


            // It's crucial to HTML encode the entire string AFTER applying
            // desired formatting to prevent XSS attacks if any unformatted user input
            // remains or if formatting rules are bypassed.
            // For this specific case, we're replacing specific patterns, but a general HTML encode
            // on the *final* string is generally a good practice for user-generated content,
            // then use @Html.Raw in the view.
            formattedText = System.Web.HttpUtility.HtmlEncode(formattedText);

            // Now, decode the intentionally inserted HTML tags
            formattedText = formattedText.Replace("&lt;b&gt;", "<b>");
            formattedText = formattedText.Replace("&lt;/b&gt;", "</b>");
            formattedText = formattedText.Replace("&lt;i&gt;", "<i>");
            formattedText = formattedText.Replace("&lt;/i&gt;", "</i>");

            return formattedText;
        }
    }

